1	// ============================================================
2	// Shared workflow model — used by both ey/ and superaudit/
3	// ============================================================
4	
5	// ---- Agents: who does the work ----
6	
7	export type RoleAllocation = {
8	  count: number          // headcount
9	  allocation: number     // 0-1, fraction of 40h/week allocated to this workflow
10	}
11	
12	export type Agents = {
13	  human?: {
14	    team: Record<string, number | RoleAllocation>
15	    // Root engagement: plain numbers = total available headcount (roster)
16	    //   e.g. { "Partner": 2, "Senior Manager": 6 }
17	    // Leaf workflows: RoleAllocation = who's on this + how much
18	    //   e.g. { "Partner": { count: 1, allocation: 0.3 },
19	    //          "Manager": { count: 3, allocation: 0.9 } }
20	  }
21	  ai?: {
22	    cost_usd: number
23	  }
24	}
25	
26	// ---- Workflow: pure work structure ----
27	
28	export type Workflow = {
29	  id: string
30	  name: string
31	  description: string
32	
33	  // Fractal nesting
34	  sub_workflows?: Workflow[]
35	
36	  // I/O for DAG inference (matched by type name string)
37	  inputs?: string[]
38	  outputs?: string[]
39	
40	  // Timing (weeks from engagement start)
41	  timing?: { start: number; end: number }
42	
43	  // Regulatory requirements this workflow satisfies
44	  requirement_ids?: string[]
45	
46	  // Who does the work — team composition + AI compute
47	  agents: Agents
48	}
49	
50	// ---- WorkflowCost: wraps a Workflow with computed cost data ----
51	
52	export type WorkflowCost = {
53	  workflow: Workflow
54	
55	  // All computed by computeCost
56	  computed_hours: number                 // human hours from team × timing × allocation
57	  role_hours: Record<string, number>     // hours per role
58	  direct_human: number
59	  direct_ai: number
60	  overhead: number
61	  total: number
62	
63	  // Fractal nesting — mirrors workflow.sub_workflows
64	  sub_workflow_costs?: WorkflowCost[]
65	}
66	
67	// ---- CostConfig: engagement-wide pricing ----
68	
69	export type CostConfig = {
70	  name: string
71	  role_rates: { role: string; cost_per_hour: number }[]
72	  default_allocation: number   // fallback if leaf uses plain number instead of RoleAllocation
73	  overhead: {
74	    categories: { name: string; rate: number; description: string }[]
75	    total_rate: number
76	    engagements_amortized: number
77	  }
78	}
79	
80	// ---- Requirement ----
81	
82	export type Requirement = {
83	  id: string
84	  description: string
85	  source: string
86	}
87	
88	// ---- Computed metrics (for comparison page) ----
89	
90	export type EngagementMetrics = {
91	  total_cost: number
92	  labor_hours: number
93	  duration_weeks: number
94	  humans_required: number
95	}
96	
97	// ---- Helpers ----
98	
99	export function getWorkerType(w: Workflow): "ai" | "human" | "ai_human" {
100	  const hasHuman = !!w.agents.human?.team && Object.keys(w.agents.human.team).length > 0
101	  const hasAi = !!w.agents.ai
102	  if (hasHuman && hasAi) return "ai_human"
103	  if (hasAi) return "ai"
104	  return "human"
105	}
106	
107	export function getHeadcount(w: Workflow): number {
108	  if (!w.agents.human?.team) return 0
109	  let total = 0
110	  for (const alloc of Object.values(w.agents.human.team)) {
111	    total += typeof alloc === "number" ? alloc : alloc.count
112	  }
113	  return total
114	}
115	
116	function mergeRoleHours(children: WorkflowCost[]): Record<string, number> {
117	  const merged: Record<string, number> = {}
118	  for (const c of children) {
119	    for (const [role, hrs] of Object.entries(c.role_hours)) {
120	      merged[role] = (merged[role] ?? 0) + hrs
121	    }
122	  }
123	  return merged
124	}
125	
126	// ---- Cost computation (recursive, fractal) ----
127	
128	export function computeCost(wc: WorkflowCost, config: CostConfig): WorkflowCost {
129	  if (wc.sub_workflow_costs) {
130	    const computed = wc.sub_workflow_costs.map(c => computeCost(c, config))
131	    return {
132	      ...wc,
133	      sub_workflow_costs: computed,
134	      computed_hours: computed.reduce((s, c) => s + c.computed_hours, 0),
135	      role_hours: mergeRoleHours(computed),
136	      direct_human: computed.reduce((s, c) => s + c.direct_human, 0),
137	      direct_ai: computed.reduce((s, c) => s + c.direct_ai, 0),
138	      overhead: computed.reduce((s, c) => s + c.overhead, 0),
139	      total: computed.reduce((s, c) => s + c.total, 0),
140	    }
141	  }
142	
143	  const { agents, timing } = wc.workflow
144	  const weeks = (timing?.end ?? 0) - (timing?.start ?? 0)
145	
146	  // Compute per-role hours from team × weeks × 40h × allocation
147	  const role_hours: Record<string, number> = {}
148	  if (agents.human?.team) {
149	    for (const [role, alloc] of Object.entries(agents.human.team)) {
150	      const { count, allocation } =
151	        typeof alloc === "number"
152	          ? { count: alloc, allocation: config.default_allocation }
153	          : alloc
154	      role_hours[role] = count * weeks * 40 * allocation
155	    }
156	  }
157	  const computed_hours = Object.values(role_hours).reduce((a, b) => a + b, 0)
158	
159	  // Cost from role hours × rates
160	  const rateMap = Object.fromEntries(config.role_rates.map(r => [r.role, r.cost_per_hour]))
161	  const direct_human = Object.entries(role_hours)
162	    .reduce((s, [role, hrs]) => s + hrs * (rateMap[role] ?? 0), 0)
163	  const direct_ai = agents.ai?.cost_usd ?? 0
164	
165	  const effectiveRate = config.overhead.total_rate / config.overhead.engagements_amortized
166	  const overhead = (direct_human + direct_ai) * effectiveRate
167	
168	  return {
169	    ...wc,
170	    computed_hours,
171	    role_hours,
172	    direct_human,
173	    direct_ai,
174	    overhead,
175	    total: direct_human + direct_ai + overhead,
176	  }
177	}
178	
179	// ---- Allocation validation ----
180	
181	export type AllocationEntry = {
182	  week: number
183	  role: string
184	  allocated: number
185	  available: number
186	  overAllocated: boolean
187	}
188	
189	export type AllocationReport = {
190	  entries: AllocationEntry[]
191	  valid: boolean
192	  violations: AllocationEntry[]
193	}
194	
195	function collectLeaves(w: Workflow): Workflow[] {
196	  if (!w.sub_workflows?.length) return [w]
197	  return w.sub_workflows.flatMap(collectLeaves)
198	}
199	
200	export function validateAllocation(root: Workflow, config: CostConfig): AllocationReport {
201	  // Extract roster from root
202	  const roster: Record<string, number> = {}
203	  if (root.agents.human?.team) {
204	    for (const [role, val] of Object.entries(root.agents.human.team)) {
205	      roster[role] = typeof val === "number" ? val : val.count
206	    }
207	  }
208	
209	  // Collect all leaves with timing + team
210	  const leaves = collectLeaves(root).filter(w => w.timing && w.agents.human?.team)
211	
212	  // Find time range
213	  const starts = leaves.map(w => w.timing!.start)
214	  const ends = leaves.map(w => w.timing!.end)
215	  if (!starts.length) return { entries: [], valid: true, violations: [] }
216	  const minWeek = Math.floor(Math.min(...starts))
217	  const maxWeek = Math.ceil(Math.max(...ends))
218	
219	  const entries: AllocationEntry[] = []
220	
221	  for (let week = minWeek; week < maxWeek; week++) {
222	    // Sum allocation per role across active leaves
223	    const allocated: Record<string, number> = {}
224	    for (const leaf of leaves) {
225	      if (leaf.timing!.start <= week && week < leaf.timing!.end) {
226	        for (const [role, alloc] of Object.entries(leaf.agents.human!.team)) {
227	          const { count, allocation } =
228	            typeof alloc === "number"
229	              ? { count: alloc, allocation: config.default_allocation }
230	              : alloc
231	          allocated[role] = (allocated[role] ?? 0) + count * allocation
232	        }
233	      }
234	    }
235	
236	    // Compare to roster
237	    for (const [role, amount] of Object.entries(allocated)) {
238	      const available = roster[role] ?? 0
239	      entries.push({
240	        week,
241	        role,
