import { engagement } from './data/ey/engagement';

// Check which PCAOB requirements are only on parent nodes (not on any leaf)
function collectAll(w: any): any[] {
  return [w, ...(w.sub_workflows ?? []).flatMap(collectAll)];
}
function collectLeaves(w: any): any[] {
  if (!w.sub_workflows?.length) return [w];
  return w.sub_workflows.flatMap(collectLeaves);
}

const all = collectAll(engagement);
const leaves = collectLeaves(engagement);
